import React from "react";
import {AppBar, Typography,Toolbar, Button} from "@material-ui/core";
// import createMuiTheme from "@material-ui/core/styles/createMuiTheme";
import InstagramIcon from '@material-ui/icons/Instagram';
import LinkedInIcon from '@material-ui/icons/LinkedIn';
import GitHubIcon from '@material-ui/icons/GitHub';
import IconButton from "@material-ui/core/IconButton";
import {BrowserRouter as Router } from 'react-router-dom';
import Resume from '../YuvalResume.pdf';

const onResumeClick = () =>{
    window.open(Resume);
}

export default class NavBar extends React.Component{
    render() {
        const handleClick = () => {
            window.open(props);
        }
        return(
                <AppBar position="static" color = "primary">
                    <Toolbar>
                        <Typography>
                            <Button color = "inherit" onClick={onResumeClick}>
                                Resume
                            </Button>
                        </Typography>
                        <Typography style={{flexGrow: 1}}>
                            <Button color = "inherit">
                                Activities
                            </Button>
                        </Typography>
                        <Typography>
                            <IconButton onClick={()=> this.handleClick('https://github.com/yuvalkansal')}>
                                <InstagramIcon allowReorder="yes"/>
                            </IconButton>
                            <IconButton onClick={()=> this.handleClick('https://www.linkedin.com/in/yuval-kansal-0a1643193/')}>
                                <LinkedInIcon />
                            </IconButton>
                            <IconButton onClick={()=> this.handleClick('https://www.instagram.com/yuvikansal/')}>
                                <GitHubIcon />
                            </IconButton>

                        </Typography>
                    </Toolbar>
                </AppBar>
        )
    }
}
